package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnAppUpgradeProxy struct {
	automation.UnimplementedOnAppUpgradeServer
	client automation.OnAppUpgradeClient
}

func init() {
	proxyutil.Register(&automation.OnAppUpgrade_ServiceDesc, NewOnAppUpgradeProxy)
}
func NewOnAppUpgradeProxy(cc grpc.ClientConnInterface) automation.OnAppUpgradeServer {
	return &OnAppUpgradeProxy{client: automation.NewOnAppUpgradeClient(cc)}
}
func (p *OnAppUpgradeProxy) OnAppUpgrade(ctx context.Context, in *events.AppUpgrade) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[events.AppUpgrade, automation.HandlerResult](p.client.OnAppUpgrade)(ctx, in)
}
